 23→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 24→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 25→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 26→
 27→  return {
 28→    id: generateId('floor'),
 29→    name,
 30→    levelIndex,
 31→    elevation,
 32→    floorToFloorHeight,
 33→    walls: [],
 34→    rooms: [],
 35→    doors: [],
 36→    windows: [],
 37→    columns: [],
 38→    beams: [],
 39→    stairs: [],
 40→    landings: [],
 41→    fixtures: [],
 42→    annotations: [],
 43→    annotationSettings: createAnnotationSettings(),
 44→    slabs: [],
 45→    sectionCuts: [],
 46→  };
 47→}
