 1→import { createDoor } from '@/domain/models';
 2→import { distanceToSegment } from '@/geometry/line';
 3→import { clampWallOpeningOffset, projectPointOnWall, wallLength } from '@/geometry/wallGeometry';
 4→import { DOOR_WIDTH } from '@/domain/defaults';
 5→
 6→const WALL_DETECT_RADIUS = 500; // mm
 7→
 8→function findNearestWall(modelPos, walls) {
 9→  let best = null;
10→  let bestDist = WALL_DETECT_RADIUS;
11→
12→  for (const wall of walls) {
13→    const d = distanceToSegment(modelPos, wall.start, wall.end);
14→    if (d < bestDist) {
15→      best = wall;
16→      bestDist = d;
17→    }
18→  }
19→  return best;
20→}
21→
22→function overlapsExisting(wallId, offset, width, doors, windows) {
23→  const halfW = width / 2;
24→  const min = offset - halfW;
25→  const max = offset + halfW;
26→
27→  for (const d of doors) {
28→    if (d.wallId !== wallId) continue;
29→    const dMin = d.offset - d.width / 2;
30→    const dMax = d.offset + d.width / 2;
31→    if (min < dMax && max > dMin) return true;
32→  }
33→  for (const w of windows) {
34→    if (w.wallId !== wallId) continue;
35→    const wMin = w.offset - w.width / 2;
36→    const wMax = w.offset + w.width / 2;
37→    if (min < wMax && max > wMin) return true;
38→  }
39→  return false;
40→}
41→
42→export function createDoorPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId }) {
43→  return {
44→    onMouseMove(modelPos, e, toolState) {
45→      const floor = getFloor(activeFloorId);
46→      if (!floor) return;
47→      const wall = findNearestWall(modelPos, floor.walls);
48→
49→      if (wall) {
50→        const offset = projectPointOnWall(wall, modelPos);
51→        const clampedOffset = clampWallOpeningOffset(wallLength(wall), DOOR_WIDTH, offset);
52→        const blocked = overlapsExisting(wall.id, clampedOffset, DOOR_WIDTH, floor.doors, floor.windows);
53→
54→        editorDispatch({
55→          type: 'UPDATE_TOOL_STATE',
56→          payload: {
57→            previewWallId: wall.id,
58→            previewOffset: clampedOffset,
59→            previewBlocked: blocked,
60→            openDirection: toolState.openDirection || 'left',
61→          },
62→        });
63→      } else {
64→        editorDispatch({
65→          type: 'UPDATE_TOOL_STATE',
66→          payload: { previewWallId: null, previewOffset: null, previewBlocked: false, openDirection: toolState.openDirection || 'left' },
67→        });
68→      }
69→    },
70→
71→    onMouseDown(modelPos, e, toolState) {
72→      if (e.button !== 0) return;
73→      if (!toolState.previewWallId || toolState.previewBlocked) return;
74→
75→      const openDir = toolState.openDirection || 'left';
76→      const door = createDoor(toolState.previewWallId, toolState.previewOffset, DOOR_WIDTH, openDir);
77→      dispatch({ type: 'DOOR_ADD', floorId: activeFloorId, door });
78→    },
79→
80→    onKeyDown(e, toolState) {
81→      if (e.key === 'Escape') {
82→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
83→      }
84→      if (e.key === 'f' || e.key === 'F') {
85→        const flipped = toolState.openDirection === 'right' ? 'left' : 'right';
86→        editorDispatch({
87→          type: 'UPDATE_TOOL_STATE',
88→          payload: { openDirection: flipped },
89→        });
90→      }
91→    },
92→
93→    getCursor(toolState) {
94→      if (!toolState.previewWallId || toolState.previewBlocked) return 'not-allowed';
95→      return 'copy';
96→    },
97→  };
98→}
