  8→const ProjectContext = createContext(null);
  9→const HISTORY_LIMIT = 100;
 10→
 11→function snapshotProject(project) {
 12→  return JSON.stringify(project);
 13→}
 14→
 15→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 16→  const nextSnapshot = snapshotProject(nextProject);
 17→  const history = recordHistory
 18→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 19→    : state.history;
 20→
 21→  return {
 22→    ...state,
 23→    history,
 24→    future: recordHistory ? [] : state.future,
 25→    project: nextProject,
 26→    isDirty: nextSnapshot !== state.savedSnapshot,
 27→  };
 28→}
 29→
 30→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 31→  const nextFloors = state.project.floors.map((floor) => (
 32→    floor.id === floorId ? updater(floor) : floor
 33→  ));
 34→
 35→  return applyProjectUpdate(state, {
 36→    ...state.project,
 37→    updatedAt: new Date().toISOString(),
 38→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 39→  }, recordHistory);
 40→}
 41→
 42→function replaceFloors(state, floors, recordHistory = true) {
 43→  return applyProjectUpdate(state, {
 44→    ...state.project,
 45→    updatedAt: new Date().toISOString(),
 46→    floors: sortFloors(floors),
 47→  }, recordHistory);
 48→}
 49→
 50→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 51→  return {
 52→    ...project,
 53→    floors: project.floors.map((floor) => ({
 54→      ...floor,
 55→      stairs: (floor.stairs || []).map((stair) => ({
 56→        ...stair,
 57→        floorRelation: {
 58→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 59→            ? fallbackFloorId
 60→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 61→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 62→            ? fallbackFloorId
 63→            : (stair.floorRelation?.toFloorId ?? floor.id),
 64→        },
 65→      })),
 66→    })),
 67→    sheets: (project.sheets || []).map((sheet) => ({
 68→      ...sheet,
 69→      viewports: (sheet.viewports || []).map((viewport) => ({
 70→        ...viewport,
 71→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 72→          ? fallbackFloorId
 73→          : viewport.sourceFloorId,
 74→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 75→          ? null
 76→          : viewport.sourceRefId,
 77→      })),
 78→    })),
 79→  };
 80→}
 81→
 82→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 83→  const nextWall = { ...existingWall, ...wallUpdate };
 84→
 85→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 86→    nextWall.startAttachment = null;
 87→  }
 88→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 89→    nextWall.endAttachment = null;
 90→  }
 91→
 92→  return syncWallAttachmentPoints(nextWall, columns);
 93→}
 94→
 95→function clampWallMountedOpenings(openings, wallId, nextWallLength) {
 96→  return openings.map((opening) => {
 97→    if (opening.wallId !== wallId) return opening;
 98→
 99→    const nextOffset = clampWallOpeningOffset(nextWallLength, opening.width, opening.offset);
100→    return nextOffset === opening.offset ? opening : { ...opening, offset: nextOffset };
101→  });
102→}
103→
104→function projectReducer(state, action) {
105→  switch (action.type) {
106→    case 'PROJECT_NEW': {
107→      const newProject = {
108→        ...action.project,
109→        floors: sortFloors(action.project.floors || []),
110→      };
111→      return {
112→        project: newProject,
113→        isDirty: false,
114→        lastSavedAt: null,
115→        savedSnapshot: snapshotProject(newProject),
116→        history: [],
117→        future: [],
118→      };
119→    }
120→
121→    case 'PROJECT_LOAD': {
122→      const loadedProject = {
123→        ...action.project,
124→        floors: sortFloors(action.project.floors || []),
125→      };
126→      return {
127→        project: loadedProject,
128→        isDirty: false,
129→        lastSavedAt: action.savedAt || null,
130→        savedSnapshot: snapshotProject(loadedProject),
131→        history: [],
132→        future: [],
133→      };
134→    }
135→
136→    case 'PROJECT_SET_NAME':
137→      return applyProjectUpdate(state, {
138→        ...state.project,
139→        name: action.name,
140→        updatedAt: new Date().toISOString(),
141→      });
142→
143→    case 'PROJECT_UPDATE':
144→      return applyProjectUpdate(state, {
145→        ...state.project,
146→        ...action.updates,
147→        updatedAt: new Date().toISOString(),
148→      });
149→
150→    case 'FLOOR_ADD':
151→      return replaceFloors(state, [...state.project.floors, action.floor]);
152→
153→    case 'FLOOR_UPDATE':
154→      return updateFloor(state, action.floor.id, (floor) => {
155→        const mergedFloor = {
156→          ...floor,
157→          ...action.floor,
158→        };
159→        const nextElevation = getFloorElevation(mergedFloor);
160→        const deltaElevation = nextElevation - getFloorElevation(floor);
161→        return {
162→          ...shiftFloorAbsoluteElements({
163→            ...mergedFloor,
164→            elevation: getFloorElevation(floor),
165→          }, deltaElevation),
166→          elevation: nextElevation,
167→        };
168→      }, true, { sort: true });
169→
170→    case 'FLOOR_DUPLICATE': {
171→      const duplicatedFloor = action.floor;
172→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
173→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
174→
175→      const shiftedFloors = state.project.floors.map((floor) => {
176→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
177→
178→        const previousLevelIndex = getFloorLevelIndex(floor);
179→        return shiftFloorElevationData({
180→          ...floor,
181→          name: floor.name === getDefaultFloorName(previousLevelIndex)
182→            ? getDefaultFloorName(previousLevelIndex + 1)
183→            : floor.name,
184→          levelIndex: previousLevelIndex + 1,
185→        }, elevationShift);
186→      });
187→
188→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
189→    }
190→
191→    case 'FLOOR_DELETE': {
192→      if (state.project.floors.length <= 1) return state;
193→
194→      const nextProject = replaceDeletedFloorReferences(
195→        {
196→          ...state.project,
197→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
198→        },
199→        action.floorId,
200→        action.fallbackFloorId
201→      );
202→
203→      return applyProjectUpdate(state, {
204→        ...nextProject,
205→        updatedAt: new Date().toISOString(),
206→        floors: sortFloors(nextProject.floors),
207→      });
208→    }
209→
210→    case 'SHEET_ADD':
211→      return applyProjectUpdate(state, {
212→        ...state.project,
213→        updatedAt: new Date().toISOString(),
214→        sheets: [...(state.project.sheets || []), action.sheet],
215→      });
216→
217→    case 'SHEET_UPDATE':
218→      return applyProjectUpdate(state, {
219→        ...state.project,
220→        updatedAt: new Date().toISOString(),
221→        sheets: (state.project.sheets || []).map((sheet) => (
222→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
223→        )),
224→      });
225→
226→    case 'SHEET_DELETE':
227→      return applyProjectUpdate(state, {
228→        ...state.project,
229→        updatedAt: new Date().toISOString(),
230→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
231→      });
232→
233→    case 'SHEET_VIEWPORT_ADD':
234→      return applyProjectUpdate(state, {
235→        ...state.project,
236→        updatedAt: new Date().toISOString(),
237→        sheets: (state.project.sheets || []).map((sheet) => (
238→          sheet.id === action.sheetId
239→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
240→            : sheet
241→        )),
242→      });
243→
244→    case 'SHEET_VIEWPORT_UPDATE':
245→      return applyProjectUpdate(state, {
246→        ...state.project,
247→        updatedAt: new Date().toISOString(),
248→        sheets: (state.project.sheets || []).map((sheet) => (
249→          sheet.id === action.sheetId
250→            ? {
251→                ...sheet,
252→                viewports: (sheet.viewports || []).map((viewport) => (
253→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
254→                )),
255→              }
256→            : sheet
257→        )),
258→      });
259→
260→    case 'SHEET_VIEWPORT_DELETE':
261→      return applyProjectUpdate(state, {
262→        ...state.project,
263→        updatedAt: new Date().toISOString(),
264→        sheets: (state.project.sheets || []).map((sheet) => (
265→          sheet.id === action.sheetId
266→            ? {
267→                ...sheet,
268→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
269→              }
270→            : sheet
271→        )),
272→      });
273→
274→    case 'WALL_ADD':
275→      return updateFloor(state, action.floorId, f => ({
276→        ...f,
277→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
278→      }));
279→
280→    case 'WALL_UPDATE':
281→      return updateFloor(state, action.floorId, f => {
282→        let updatedWall = null;
283→        const walls = f.walls.map((wall) => {
284→          if (wall.id !== action.wall.id) return wall;
285→
286→          updatedWall = mergeWallUpdate(wall, action.wall, f.columns || []);
287→          return updatedWall;
288→        });
289→
290→        if (!updatedWall) {
291→          return f;
292→        }
293→
294→        const nextWallLength = wallLength(updatedWall);
295→
296→        return {
297→          ...f,
298→          walls,
299→          doors: clampWallMountedOpenings(f.doors, updatedWall.id, nextWallLength),
300→          windows: clampWallMountedOpenings(f.windows, updatedWall.id, nextWallLength),
301→        };
302→      });
303→
304→    case 'WALL_DELETE': {
305→      const wallId = action.wallId;
306→      return updateFloor(state, action.floorId, f => ({
307→        ...f,
308→        walls: f.walls.filter(w => w.id !== wallId),
309→        doors: f.doors.filter(d => d.wallId !== wallId),
310→        windows: f.windows.filter(w => w.wallId !== wallId),
311→      }));
312→    }
