367→        beams: (f.beams || []).filter(beam => beam.id !== action.beamId),
368→      }));
369→
370→    case 'STAIR_ADD':
371→      return updateFloor(state, action.floorId, f => ({
372→        ...f,
373→        stairs: [...(f.stairs || []), action.stair],
374→      }));
375→
376→    case 'STAIR_UPDATE':
377→      return updateFloor(state, action.floorId, f => ({
378→        ...f,
379→        stairs: (f.stairs || []).map(stair => (
380→          stair.id === action.stair.id ? { ...stair, ...action.stair } : stair
381→        )),
382→      }));
383→
384→    case 'STAIR_DELETE':
