386→        ...f,
387→        stairs: (f.stairs || []).filter(stair => stair.id !== action.stairId),
388→      }));
389→
390→    case 'LANDING_ADD':
391→      return updateFloor(state, action.floorId, f => ({
392→        ...f,
393→        landings: [...(f.landings || []), action.landing],
394→      }));
395→
396→    case 'LANDING_UPDATE': {
397→      return updateFloor(state, action.floorId, f => {
398→        const nextLandings = (f.landings || []).map(l =>
399→          l.id === action.landing.id ? { ...l, ...action.landing } : l
400→        );
401→        // Cascade: sync all stairs attached to this landing
402→        const nextStairs = (f.stairs || []).map(stair => {
403→          const attachedToStart = stair.startLandingAttachment?.landingId === action.landing.id;
404→          const attachedToEnd = stair.endLandingAttachment?.landingId === action.landing.id;
405→          if (!attachedToStart && !attachedToEnd) return stair;
406→          return syncStairLandingAttachment(stair, nextLandings);
407→        });
408→        return { ...f, landings: nextLandings, stairs: nextStairs };
409→      });
410→    }
411→
412→    case 'LANDING_DELETE':
413→      return updateFloor(state, action.floorId, f => ({
414→        ...f,
415→        landings: (f.landings || []).filter(l => l.id !== action.landingId),
416→        stairs: (f.stairs || []).map(stair => {
417→          let next = stair;
418→          if (stair.startLandingAttachment?.landingId === action.landingId) {
419→            next = { ...next, startLandingAttachment: null };
420→          }
421→          if (stair.endLandingAttachment?.landingId === action.landingId) {
422→            next = { ...next, endLandingAttachment: null };
423→          }
424→          return next;
425→        }),
