519→      }));
520→
521→    case 'FLOOR_REPLACE':
522→      return updateFloor(state, action.floorId, () => ({
523→        ...action.floor,
524→      }), true, { sort: true });
525→
526→    case 'FIXTURE_ADD':
527→      return updateFloor(state, action.floorId, f => ({
528→        ...f, fixtures: [...(f.fixtures || []), action.fixture],
529→      }));
530→    case 'FIXTURE_UPDATE':
531→      return updateFloor(state, action.floorId, f => ({
532→        ...f,
533→        fixtures: (f.fixtures || []).map(fix =>
534→          fix.id === action.fixture.id ? { ...fix, ...action.fixture } : fix
535→        ),
536→      }));
537→    case 'FIXTURE_DELETE':
538→      return updateFloor(state, action.floorId, f => ({
