562→      });
563→    case 'COLUMN_DELETE':
564→      return updateFloor(state, action.floorId, f => ({
565→        ...f,
566→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
567→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
568→        beams: (f.beams || []).filter(beam => (
569→          beam.startRef?.id !== action.columnId && beam.endRef?.id !== action.columnId
570→        )),
571→      }));
572→
573→    case 'MARK_SAVED':
574→      return {
575→        ...state,
576→        isDirty: false,
577→        lastSavedAt: new Date().toISOString(),
578→        savedSnapshot: snapshotProject(state.project),
579→      };
580→
581→    case 'UNDO': {
582→      if (state.history.length === 0) return state;
583→      const previousProject = state.history[state.history.length - 1];
584→      return {
585→        ...state,
586→        project: previousProject,
587→        history: state.history.slice(0, -1),
588→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
589→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
590→      };
591→    }
592→
593→    case 'REDO': {
594→      if (state.future.length === 0) return state;
595→      const nextProject = state.future[0];
596→      return {
597→        ...state,
598→        project: nextProject,
599→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
600→        future: state.future.slice(1),
601→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
602→      };
603→    }
604→
605→    default:
606→      return state;
607→  }
608→}
