 37→function useUnits() {
 38→  const [unit, setUnit] = useState('mm');
 39→  const isMm = unit === 'mm';
 40→  return {
 41→    unit,
 42→    setUnit,
 43→    suffix: isMm ? 'mm' : 'm',
 44→    toDisplay: (mm) => isMm ? +mm.toFixed(1) : +(mm / 1000).toFixed(4),
 45→    fromDisplay: (v) => isMm ? v : v * 1000,
 46→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 47→  };
 48→}
